{"success": true, "name": "professional-services-website", "file": "references/section-components-pattern.md", "content": "# Section Components Pattern — Pages Router Standalone

## Architecture

Pages Router sites use a `SECTION_MAP` in both `index.tsx` and `[slug].tsx` to dispatch section IDs to React components. Page config JSON files define which sections render and what content key they read.

### Data Flow

```
page config (nexa-pages/servicios.json)
  └── sections: [
        { id: "hero", content: "servicesPage.hero" },
        { id: "pillars", content: "servicesPage.detail" }
      ]
          │
          ▼
  getServerSideProps → loads content/es.json + images.json
          │
          ▼
  SECTION_MAP[section.id] → renders component with:
    - pageContent: sectionData (resolved section content)
    - images: images manifest (for @src: / @img: resolution)
```

### SECTION_MAP is shared between index.tsx and [slug].tsx
Both files need the same `SECTION_MAP` because both can render the same section IDs. Keep them in sync.

### Component receives resolved data directly (not the full pageContent)
The `[slug].tsx` dispatcher resolves `sectionData = resolveContent(content, section.content)` and passes it as `pageContent`:

```tsx
if (Component) {
  const sectionData = resolveContent(content, section.content || section.id)
  return <Component key={key} pageContent={sectionData || pageContent} data={sectionData} images={images} />
}
```

This means components should treat `pageContent` as their DIRECT data, NOT look for `pageContent.hero` or `pageContent.faq`. Accept a `data` fallback for backward compatibility:

```tsx
export function FaqSection({ pageContent, data }: SectionProps) {
  const d = data || pageContent || {}
  const items = d.items || []
  ...
}
```

## Component Templates

### Accordion Section (FAQ, Privacy)
```tsx
export function FaqSection({ pageContent, data }: SectionProps) {
  const d = data || pageContent || {}
  const items = d.items || []
  if (!items.length) return null
  const [open, setOpen] = React.useState<number | null>(null)
  return (
    <section>
      {d.eyebrow && <p>{d.eyebrow}</p>}
      {d.title && <h2>{d.title}</h2>}
      {items.map((item, i) => {
        const question = item.pregunta || item.question || item.title || item.q
        const answer = item.respuesta || item.answer || item.description || item.body || item.a
        return (
          <div key={i}>
            <button onClick={() => setOpen(open === i ? null : i)}>
              <span>{question}</span>
              <span>{open === i ? '▾' : '▸'}</span>
            </button>
            {open === i && <div>{answer}</div>}
          </div>
        )
      })}
    </section>
  )
}
```

### Item Grid (Glossary, Team, Trust, Pillars)
```tsx
export function GlossarySection({ pageContent, data }: SectionProps) {
  const d = data || pageContent || {}
  const items = d.items || []
  if (!items.length) return null
  return (
    <section>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem' }}>
        {items.map((item, i) => (
          <div key={i}>
            <h4>{item.term || item.title || item.q}</h4>
            <p>{item.definition || item.description || item.body || item.a}</p>
          </div>
        ))}
      </div>
    </section>
  )
}
```

### Blog Post Grid
```tsx
export function BlogSection({ pageContent, data, images }: SectionProps) {
  const d = data || pageContent || {}
  const posts = d.posts || []
  return (
    <section>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem' }}>
        {posts.map((post, i) => {
          const postImg = resolveImage(images, `@img:blog.${post.image}`) || post.coverImage
          return (
            <article key={i}>
              {postImg && <img src={postImg} alt={post.title} />}
              <h3>{post.title}</h3>
              {post.excerpt && <p>{post.excerpt}</p>}
              {post.slug && <a href={`/blog/${post.slug}`}>Leer más →</a>}
            </article>
          )
        })}
      </div>
    </section>
  )
}
```

